REPLACE INTO `recipes` (`id`, `category_id`, `title`, `slug`, `thumbnail_url`, `summary`, `content`, `ingredients`, `steps`, `nutrition`, `cooking_time_minutes`, `servings`, `difficulty`, `is_featured`, `status`, `created_at`, `updated_at`, `deleted_at`) VALUES ('912fb6f6-673f-4c23-a269-efe322b1d7c9','175bca55-9fc6-428c-b361-502935baac30','Gỏi cuốn','goi-cuon','/uploads/recipes/413a621c7b4b464dafb8bb13256a2d17.jpg','Gỏi cuốn là món ăn truyền thống nổi tiếng của Việt Nam, kết hợp hài hòa giữa tôm, thịt, bún tươi và các loại rau sống được cuốn trong lớp bánh tráng mềm dai. Món ăn mang hương vị thanh mát, ít dầu mỡ, giàu dinh dưỡng và thường được dùng kèm nước chấm đậm đà, rất phù hợp cho những bữa ăn nhẹ hoặc thực đơn ăn uống lành mạnh.','Gỏi cuốn là một trong những món ăn đặc trưng của ẩm thực Việt Nam, được nhiều thực khách trong và ngoài nước yêu thích. Khác với các món chiên rán, gỏi cuốn sử dụng nguyên liệu tươi sống hoặc luộc chín như tôm, thịt ba chỉ, bún tươi, xà lách, hẹ và các loại rau thơm, sau đó cuốn gọn trong bánh tráng. Chính sự kết hợp này tạo nên hương vị thanh nhẹ, tươi ngon và cân bằng dinh dưỡng.\r\n\r\nĐiểm hấp dẫn của gỏi cuốn nằm ở sự đa dạng về nguyên liệu và nước chấm. Món ăn có thể dùng cùng nước mắm chua ngọt hoặc tương đậu phộng béo thơm, giúp tăng thêm hương vị. Không chỉ ngon miệng, gỏi cuốn còn là lựa chọn lý tưởng cho những người yêu thích thực phẩm ít dầu mỡ, giàu chất xơ và protein.','[{\""name\"":\""l\\u00E1 b\\u00E1nh tr\\u00E1ng\"",\""quantity\"":\""12\""},{\""name\"":\""t\\u00F4m t\\u01B0\\u01A1i\"",\""quantity\"":\""200\""},{\""name\"":\""th\\u1ECBt ba ch\\u1EC9\"",\""quantity\"":\""200\""},{\""name\"":\""b\\u00FAn t\\u01B0\\u01A1i\"",\""quantity\"":\""300\""},{\""name\"":\""c\\u00E2y x\\u00E0 l\\u00E1ch\"",\""quantity\"":\""1\""},{\""name\"":\""gi\\u00E1 \\u0111\\u1ED7\"",\""quantity\"":\""50\""}]','[{\""order\"":1,\""title\"":\""B\\u01B0\\u1EDBc 1: S\\u01A1 ch\\u1EBF nguy\\u00EAn li\\u1EC7u\"",\""description\"":\""Lu\\u1ED9c th\\u1ECBt ba ch\\u1EC9, \\u0111\\u1EC3 ngu\\u1ED9i r\\u1ED3i th\\u00E1i l\\u00E1t m\\u1ECFng.\\nLu\\u1ED9c t\\u00F4m, b\\u00F3c v\\u1ECF v\\u00E0 b\\u1ECF ch\\u1EC9 l\\u01B0ng.\\nTr\\u1EE5ng b\\u00FAn qua n\\u01B0\\u1EDBc n\\u00F3ng r\\u1ED3i \\u0111\\u1EC3 r\\u00E1o.\\nR\\u1EEDa s\\u1EA1ch c\\u00E1c lo\\u1EA1i rau v\\u00E0 \\u0111\\u1EC3 r\\u00E1o n\\u01B0\\u1EDBc.\""},{\""order\"":2,\""title\"":\""B\\u01B0\\u1EDBc 2: Chu\\u1EA9n b\\u1ECB b\\u00E1nh tr\\u00E1ng\"",\""description\"":\""Nh\\u00FAng b\\u00E1nh tr\\u00E1ng qua n\\u01B0\\u1EDBc s\\u1EA1ch kho\\u1EA3ng 2\\u20133 gi\\u00E2y cho m\\u1EC1m.\\nTr\\u1EA3i b\\u00E1nh tr\\u00E1ng l\\u00EAn m\\u1EB7t ph\\u1EB3ng s\\u1EA1ch.\""},{\""order\"":3,\""title\"":\""B\\u01B0\\u1EDBc 3: X\\u00E0o th\\u1ECBt\"",\""description\"":\""- L\\u00E0m n\\u00F3ng n\\u1ED3i, cho m\\u1ED9t \\u00EDt d\\u1EA7u \\u0103n.\\n- Phi th\\u01A1m h\\u00E0nh t\\u00EDm v\\u00E0 t\\u1ECFi, sau \\u0111\\u00F3 cho th\\u1ECBt \\u0111\\u00E3 \\u01B0\\u1EDBp v\\u00E0o \\u0111\\u1EA3o \\u0111\\u1EC1u \\u0111\\u1EBFn khi th\\u1ECBt s\\u0103n l\\u1EA1i.\\n- Th\\u00EAm n\\u01B0\\u1EDBc m\\u00E0u \\u0111\\u1EC3 th\\u1ECBt c\\u00F3 m\\u00E0u n\\u00E2u \\u0111\\u1EB9p.\""},{\""order\"":4,\""title\"":\""B\\u01B0\\u1EDBc 3: Cu\\u1ED1n g\\u1ECFi\"",\""description\"":\""X\\u1EBFp l\\u1EA7n l\\u01B0\\u1EE3t x\\u00E0 l\\u00E1ch, rau th\\u01A1m, b\\u00FAn, th\\u1ECBt, t\\u00F4m v\\u00E0 h\\u1EB9 l\\u00EAn b\\u00E1nh tr\\u00E1ng.\\nG\\u1EA5p hai m\\u00E9p b\\u00E1nh tr\\u00E1ng v\\u00E0o trong r\\u1ED3i cu\\u1ED9n ch\\u1EB7t tay \\u0111\\u1EC3 t\\u1EA1o h\\u00ECnh \\u0111\\u1EB9p m\\u1EAFt.\""},{\""order\"":5,\""title\"":\""B\\u01B0\\u1EDBc 4: Pha n\\u01B0\\u1EDBc ch\\u1EA5m\"",\""description\"":\""Pha n\\u01B0\\u1EDBc m\\u1EAFm v\\u1EDBi n\\u01B0\\u1EDBc, \\u0111\\u01B0\\u1EDDng, n\\u01B0\\u1EDBc c\\u1ED1t chanh, t\\u1ECFi v\\u00E0 \\u1EDBt \\u0111\\u1EC3 t\\u1EA1o v\\u1ECB chua ng\\u1ECDt h\\u00E0i h\\u00F2a.\\nHo\\u1EB7c s\\u1EED d\\u1EE5ng t\\u01B0\\u01A1ng \\u0111\\u1EADu ph\\u1ED9ng n\\u1EA5u c\\u00F9ng t\\u1ECFi phi \\u0111\\u1EC3 c\\u00F3 h\\u01B0\\u01A1ng v\\u1ECB b\\u00E9o th\\u01A1m.\""},{\""order\"":6,\""title\"":\""B\\u01B0\\u1EDBc 5: Th\\u01B0\\u1EDFng th\\u1EE9c\"",\""description\"":\""X\\u1EBFp g\\u1ECFi cu\\u1ED1n ra \\u0111\\u0129a.\\nD\\u00F9ng k\\u00E8m n\\u01B0\\u1EDBc ch\\u1EA5m v\\u00E0 rau s\\u1ED1ng \\u0111\\u1EC3 t\\u0103ng h\\u01B0\\u01A1ng v\\u1ECB.\\nTh\\u01B0\\u1EDFng th\\u1EE9c ngay sau khi cu\\u1ED1n \\u0111\\u1EC3 gi\\u1EEF \\u0111\\u01B0\\u1EE3c \\u0111\\u1ED9 t\\u01B0\\u01A1i ngon c\\u1EE7a nguy\\u00EAn li\\u1EC7u.\""}]','{\""calories\"":520,\""protein\"":29,\""carbs\"":10,\""fat\"":40}',30,3,'MEDIUM',1,1,'2026-06-26 07:11:30.731','2026-06-26 08:49:43.913',NULL);
REPLACE INTO `recipes` (`id`, `category_id`, `title`, `slug`, `thumbnail_url`, `summary`, `content`, `ingredients`, `steps`, `nutrition`, `cooking_time_minutes`, `servings`, `difficulty`, `is_featured`, `status`, `created_at`, `updated_at`, `deleted_at`) VALUES ('ce1ba7a9-1342-4d7e-b7f0-7856dc586f0e','175bca55-9fc6-428c-b361-502935baac30','Thịt kho tàu','thit-kho-tau','/uploads/recipes/413a621c7b4b464dafb8bb13256a2d17.jpg','Thịt kho trứng là món ăn truyền thống quen thuộc trong bữa cơm của người Việt, nổi bật với thịt ba chỉ mềm thơm, trứng luộc béo bùi hòa quyện trong nước kho đậm đà. Món ăn không chỉ hấp dẫn bởi hương vị mặn ngọt cân bằng mà còn gợi nhớ hương vị gia đình, đặc biệt khi dùng cùng cơm trắng nóng hổi.','Thịt kho trứng là một trong những món ăn mang đậm nét văn hóa ẩm thực Việt Nam, được nhiều gia đình yêu thích bởi hương vị thơm ngon và cách chế biến không quá cầu kỳ. Món ăn được làm từ thịt ba chỉ tươi ngon kết hợp cùng trứng gà hoặc trứng vịt luộc, sau đó kho chậm với nước màu, nước mắm và các loại gia vị truyền thống để tạo nên màu nâu cánh gián đẹp mắt cùng hương thơm hấp dẫn.\r\n\r\nĐiểm đặc trưng của thịt kho trứng là phần thịt mềm tan, lớp mỡ béo vừa phải nhưng không ngấy, hòa quyện cùng phần nạc đậm vị. Trứng sau khi kho thấm đều gia vị, có vị bùi béo và màu sắc bắt mắt. Nước kho sánh nhẹ, đậm đà, rất thích hợp để chan cùng cơm trắng hoặc ăn kèm với dưa giá, củ cải muối hay rau luộc, giúp cân bằng hương vị.\r\n\r\nKhông chỉ là món ăn thường ngày, thịt kho trứng còn xuất hiện trong những dịp lễ, Tết như biểu tượng của sự sum vầy và đủ đầy. Với hương vị truyền thống, giá trị dinh dưỡng cao và khả năng bảo quản tốt, đây luôn là lựa chọn lý tưởng cho những bữa cơm gia đình ấm cúng.','[{\""name\"":\""th\\u1ECBt ba ch\\u1EC9\"",\""quantity\"":\""500g\""},{\""name\"":\""5\\u20136 qu\\u1EA3 tr\\u1EE9ng g\\u00E0 ho\\u1EB7c 4 qu\\u1EA3 tr\\u1EE9ng v\\u1ECBt\"",\""quantity\"":\""5\""},{\""name\"":\""t\\u00E9p t\\u1ECFi b\\u0103m\"",\""quantity\"":\""3\""},{\""name\"":\""c\\u1EE7 h\\u00E0nh t\\u00EDm b\\u0103m\"",\""quantity\"":\""3\""},{\""name\"":\""qu\\u1EA3 \\u1EDBt (t\\u00F9y ch\\u1ECDn)\"",\""quantity\"":\""3\""},{\""name\"":\""qu\\u1EA3 d\\u1EEBa t\\u01B0\\u01A1i (l\\u1EA5y kho\\u1EA3ng 500ml n\\u01B0\\u1EDBc d\\u1EEBa)\"",\""quantity\"":\""200\""}]','[{\""order\"":1,\""title\"":\""B\\u01B0\\u1EDBc 1: S\\u01A1 ch\\u1EBF nguy\\u00EAn li\\u1EC7u\"",\""description\"":\""- R\\u1EEDa s\\u1EA1ch th\\u1ECBt ba ch\\u1EC9, c\\u1EAFt th\\u00E0nh mi\\u1EBFng vu\\u00F4ng kho\\u1EA3ng 3\\u20134cm.\\n- Ch\\u1EA7n th\\u1ECBt qua n\\u01B0\\u1EDBc s\\u00F4i kho\\u1EA3ng 2\\u20133 ph\\u00FAt \\u0111\\u1EC3 lo\\u1EA1i b\\u1ECF t\\u1EA1p ch\\u1EA5t, sau \\u0111\\u00F3 r\\u1EEDa s\\u1EA1ch v\\u00E0 \\u0111\\u1EC3 r\\u00E1o.\\n- Lu\\u1ED9c tr\\u1EE9ng trong kho\\u1EA3ng 8\\u201310 ph\\u00FAt, b\\u00F3c v\\u1ECF v\\u00E0 \\u0111\\u1EC3 ri\\u00EAng.\""},{\""order\"":2,\""title\"":\""B\\u01B0\\u1EDBc 2: \\u01AF\\u1EDBp th\\u1ECBt\"",\""description\"":\""- Cho th\\u1ECBt v\\u00E0o t\\u00F4 c\\u00F9ng n\\u01B0\\u1EDBc m\\u1EAFm, \\u0111\\u01B0\\u1EDDng, h\\u1EA1t n\\u00EAm, ti\\u00EAu, h\\u00E0nh t\\u00EDm v\\u00E0 t\\u1ECFi b\\u0103m.\\n- Tr\\u1ED9n \\u0111\\u1EC1u v\\u00E0 \\u01B0\\u1EDBp t\\u1EEB 30\\u201345 ph\\u00FAt \\u0111\\u1EC3 th\\u1ECBt th\\u1EA5m gia v\\u1ECB.\""},{\""order\"":3,\""title\"":\""B\\u01B0\\u1EDBc 3: X\\u00E0o th\\u1ECBt\"",\""description\"":\""- L\\u00E0m n\\u00F3ng n\\u1ED3i, cho m\\u1ED9t \\u00EDt d\\u1EA7u \\u0103n.\\n- Phi th\\u01A1m h\\u00E0nh t\\u00EDm v\\u00E0 t\\u1ECFi, sau \\u0111\\u00F3 cho th\\u1ECBt \\u0111\\u00E3 \\u01B0\\u1EDBp v\\u00E0o \\u0111\\u1EA3o \\u0111\\u1EC1u \\u0111\\u1EBFn khi th\\u1ECBt s\\u0103n l\\u1EA1i.\\n- Th\\u00EAm n\\u01B0\\u1EDBc m\\u00E0u \\u0111\\u1EC3 th\\u1ECBt c\\u00F3 m\\u00E0u n\\u00E2u \\u0111\\u1EB9p.\""},{\""order\"":4,\""title\"":\""B\\u01B0\\u1EDBc 4: Kho th\\u1ECBt\"",\""description\"":\""- \\u0110\\u1ED5 n\\u01B0\\u1EDBc d\\u1EEBa t\\u01B0\\u01A1i v\\u00E0o n\\u1ED3i sao cho ng\\u1EADp m\\u1EB7t th\\u1ECBt.\\n- \\u0110un s\\u00F4i r\\u1ED3i h\\u1EA1 nh\\u1ECF l\\u1EEDa, kho kho\\u1EA3ng 30\\u201340 ph\\u00FAt.\\n- Cho tr\\u1EE9ng \\u0111\\u00E3 lu\\u1ED9c v\\u00E0o n\\u1ED3i v\\u00E0 ti\\u1EBFp t\\u1EE5c kho th\\u00EAm 20\\u201330 ph\\u00FAt \\u0111\\u1EC3 tr\\u1EE9ng th\\u1EA5m gia v\\u1ECB.\""},{\""order\"":5,\""title\"":\""B\\u01B0\\u1EDBc 5: N\\u00EAm n\\u1EBFm v\\u00E0 ho\\u00E0n th\\u00E0nh\"",\""description\"":\""- N\\u00EAm n\\u1EBFm l\\u1EA1i cho v\\u1EEBa kh\\u1EA9u v\\u1ECB.\\n- Khi n\\u01B0\\u1EDBc kho s\\u00E1nh nh\\u1EB9, th\\u1ECBt m\\u1EC1m v\\u00E0 tr\\u1EE9ng c\\u00F3 m\\u00E0u n\\u00E2u \\u0111\\u1EB9p th\\u00EC t\\u1EAFt b\\u1EBFp.\\n- R\\u1EAFc th\\u00EAm ti\\u00EAu xay, h\\u00E0nh l\\u00E1 ho\\u1EB7c cho v\\u00E0i qu\\u1EA3 \\u1EDBt v\\u00E0o n\\u1EBFu th\\u00EDch v\\u1ECB cay.\""}]','{\""calories\"":520,\""protein\"":29,\""carbs\"":10,\""fat\"":40}',60,3,'MEDIUM',1,1,'2026-06-26 06:53:46.043','2026-06-26 06:53:46.043',NULL);
REPLACE INTO `recipes` (`id`, `category_id`, `title`, `slug`, `thumbnail_url`, `summary`, `content`, `ingredients`, `steps`, `nutrition`, `cooking_time_minutes`, `servings`, `difficulty`, `is_featured`, `status`, `created_at`, `updated_at`, `deleted_at`) VALUES ('r1000001-0000-4000-8000-000000000001','c1000001-0000-4000-8000-000000000001','Phở bò tái','pho-bo-tai','/uploads/recipes/e1b42f42955a460f9039c3ba7f7a0280.png','Phở bò với nước dùng trong, thịt bò tái mềm và rau thơm đầy đủ.','Phở bò là món ăn biểu tượng của ẩm thực Việt Nam. Nước dùng ninh xương bò trong vắt, thơm quế hồi, ăn kèm bánh phở, thịt bò, hành, ngò gai và chanh.','[{\""name\"":\""B\\u00E1nh ph\\u1EDF\"",\""quantity\"":\""500g\""},{\""name\"":\""Th\\u1ECBt b\\u00F2 g\\u1EA7u\"",\""quantity\"":\""300g\""},{\""name\"":\""H\\u00E0nh t\\u00E2y\"",\""quantity\"":\""2 c\\u1EE7\""},{\""name\"":\""G\\u1EEBng\"",\""quantity\"":\""1 c\\u1EE7\""},{\""name\"":\""Qu\\u1EBF, h\\u1ED3i\"",\""quantity\"":\""v\\u00E0i c\\u00E1i\""}]','[{\""order\"":1,\""title\"":\""Ninh n\\u01B0\\u1EDBc d\\u00F9ng\"",\""description\"":\""Lu\\u1ED9c x\\u01B0\\u01A1ng b\\u00F2 3-4 gi\\u1EDD, v\\u1EDBt b\\u1ECDt, th\\u00EAm gia v\\u1ECB.\""},{\""order\"":2,\""title\"":\""Ch\\u1EA7n b\\u00E1nh ph\\u1EDF\"",\""description\"":\""Tr\\u1EE5ng b\\u00E1nh ph\\u1EDF 30 gi\\u00E2y, x\\u1EBFp v\\u00E0o t\\u00F4.\""},{\""order\"":3,\""title\"":\""Th\\u01B0\\u1EDFng th\\u1EE9c\"",\""description\"":\""X\\u1EBFp th\\u1ECBt, chan n\\u01B0\\u1EDBc d\\u00F9ng n\\u00F3ng, th\\u00EAm rau v\\u00E0 gia v\\u1ECB.\""}]','{\""calories\"":520,\""protein\"":32,\""carbs\"":65,\""fat\"":14}',180,2,'MEDIUM',1,1,'2026-06-26 08:56:48.962','2026-06-26 09:07:46.114',NULL);
