REPLACE INTO `recipes` (`id`, `category_id`, `title`, `slug`, `thumbnail_url`, `summary`, `content`, `ingredients`, `steps`, `nutrition`, `cooking_time_minutes`, `servings`, `difficulty`, `is_featured`, `status`, `created_at`, `updated_at`, `deleted_at`) VALUES ('r1000005-0000-4000-8000-000000000005','c1000003-0000-4000-8000-000000000003','Chè ba màu','che-ba-mau','/uploads/recipes/f31b32a847654adf8df3e832dbffac57.png','Chè ba màu mát lạnh với đậu xanh, đậu đỏ và bột báng.','Chè ba màu là món tráng miệng quen thuộc miền Nam, vị ngọt than, thơm lá dứa và nước cốt dừa.','[{\""name\"":\""\\u0110\\u1EADu xanh\"",\""quantity\"":\""100g\""},{\""name\"":\""\\u0110\\u1EADu \\u0111\\u1ECF\"",\""quantity\"":\""100g\""},{\""name\"":\""B\\u1ED9t b\\u00E1ng\"",\""quantity\"":\""50g\""},{\""name\"":\""\\u0110\\u01B0\\u1EDDng ph\\u00E8n\"",\""quantity\"":\""150g\""},{\""name\"":\""N\\u01B0\\u1EDBc c\\u1ED1t d\\u1EEBa\"",\""quantity\"":\""400ml\""}]','[{\""order\"":1,\""title\"":\""N\\u1EA5u \\u0111\\u1EADu\"",\""description\"":\""N\\u1EA5u ch\\u00EDn \\u0111\\u1EADu xanh, \\u0111\\u1EADu \\u0111\\u1ECF ri\\u00EAng.\""},{\""order\"":2,\""title\"":\""N\\u1EA5u b\\u1ED9t b\\u00E1ng\"",\""description\"":\""H\\u00F2a b\\u1ED9t b\\u00E1ng, n\\u1EA5u trong.\""},{\""order\"":3,\""title\"":\""Ho\\u00E0n thi\\u1EC7n\"",\""description\"":\""X\\u1EBFp l\\u1EDBp, r\\u01B0\\u1EDBi n\\u01B0\\u1EDBc c\\u1ED1t d\\u1EEBa, th\\u00EAm \\u0111\\u00E1.\""}]','{\""calories\"":280,\""protein\"":8,\""carbs\"":58,\""fat\"":4}',90,4,'MEDIUM',1,1,'2026-06-26 08:56:48.964','2026-06-28 00:35:52.663',NULL);
