REPLACE INTO `blogs` (`id`, `title`, `slug`, `thumbnail_url`, `summary`, `content`, `status`, `created_at`, `updated_at`, `deleted_at`) VALUES ('b1000001-0000-4000-8000-000000000001','5 mẹo nấu phở bò ngon như quán','5-meo-nau-pho-bo-ngon-nhu-quan','/uploads/blogs/7a695bc74aec410ca37c163a5e4cf1a8.png','Bí quyết ninh nước dùng, chần bánh và chọn thịt bò giúp phở thơm ngon hơn.','Nước dùng phở quyết định 80% hương vị món ăn. Hãy vớt bọt thường xuyên khi ninh xương, rang thơm gia vị trước khi cho vào nồi. Khi chần bánh phở, chỉ cần 20-30 giây để bánh mềm dai. Thịt bò nên thái mỏng, trụng qua nước sôi trước khi xếp tô.','PUBLISHED','2026-06-26 08:56:48.969','2026-06-28 01:54:41.243',NULL);
REPLACE INTO `blogs` (`id`, `title`, `slug`, `thumbnail_url`, `summary`, `content`, `status`, `created_at`, `updated_at`, `deleted_at`) VALUES ('b1000002-0000-4000-8000-000000000002','Nguyên liệu sạch cho bữa cơm gia đình','nguyen-lieu-sach-cho-bua-com-gia-dinh',NULL,'Cách chọn rau củ quả tươi và bảo quản đúng cách trong tủ lạnh.','Ưu tiên mua rau củ theo mùa, chọn lá xanh tươi, không úa vàng. Rau thơm nên bọc giấy ẩm trước khi cất tủ lạnh. Thịt cá nên mua tại nguồn uy tín, kiểm tra mùi và độ tươi trước khi chế biến.','PUBLISHED','2026-06-26 08:56:48.970','2026-06-28 01:54:41.243',NULL);
REPLACE INTO `blogs` (`id`, `title`, `slug`, `thumbnail_url`, `summary`, `content`, `status`, `created_at`, `updated_at`, `deleted_at`) VALUES ('b1000003-0000-4000-8000-000000000003','Cách chọn cá tươi cho món canh','cach-chon-ca-tuoi-cho-mon-canh','/uploads/blogs/b2be0453ff8345e69b6fb7403b8e6fca.png','Nhận biết cá tươi qua mắt, mùi và độ săn chắc của thịt.','Cá tươi thường có mắt trong, vảy bám chắc, mang đỏ hoặc hồng tùy loại. Khi ấn nhẹ, thịt cá săn lại nhanh. Tránh chọn cá mắt đục, mùi tanh gắt hoặc da nhớt nhầy.','PUBLISHED','2026-06-26 08:56:48.970','2026-06-28 01:54:41.243',NULL);
REPLACE INTO `blogs` (`id`, `title`, `slug`, `thumbnail_url`, `summary`, `content`, `status`, `created_at`, `updated_at`, `deleted_at`) VALUES ('b1000004-0000-4000-8000-000000000004','Bí quyết nướng thịt mềm không bị khô','bi-quyet-nuong-thit-mem-khong-bi-kho','/uploads/blogs/3dfd15c1a5f9466c94eac55307be5532.png','Ướp gia vị đủ thời gian và kiểm soát nhiệt độ lò giúp thịt nướng mềm, thơm.','Nên ướp thịt ít nhất 30 phút với tỏi, dầu ăn và gia vị. Nướng ở nhiệt độ 180°C, lật đều hai mặt. Có thể quết mật ong hoặc nước dừa để giữ độ ẩm.','PUBLISHED','2026-06-26 08:56:48.970','2026-06-28 01:54:41.243',NULL);
REPLACE INTO `blogs` (`id`, `title`, `slug`, `thumbnail_url`, `summary`, `content`, `status`, `created_at`, `updated_at`, `deleted_at`) VALUES ('b1000005-0000-4000-8000-000000000005','Gợi ý thực đơn 7 ngày cho gia đình bận rộn','goi-y-thuc-don-7-ngay-cho-gia-dinh-ban-ron','/uploads/blogs/c3d4731191764364a28f1940475989bb.png','Thực đơn cân bằng dinh dưỡng, dễ nấu và tiết kiệm thời gian.','Luân phiên món canh, món xào và món nướng trong tuần giúp bữa ăn đa dạng hơn. Chuẩn bị sẵn nguyên liệu cuối tuần, tận dụng thực phẩm tồn tủ lạnh để giảm lãng phí.','PUBLISHED','2026-06-26 08:56:48.970','2026-06-28 01:54:41.243',NULL);
